+        await sendMessageSignal(target, chunk, {
+          baseUrl,
+          account,
+          maxBytes,
+        });
+      }
+    } else {
+      let first = true;
+      for (const url of mediaList) {
+        const caption = first ? text : "";
+        first = false;
+        await sendMessageSignal(target, caption, {
+          baseUrl,
+          account,
+          mediaUrl: url,
+          maxBytes,
