+        Body: body,
+        From: isGroup ? `group:${groupId}` : `signal:${sender}`,
+        To: isGroup ? `group:${groupId}` : `signal:${sender}`,
+        ChatType: isGroup ? "group" : "direct",
+        GroupSubject: isGroup ? groupName ?? undefined : undefined,
